        int val = (int)nums[i];
        if (val == 1) {
            ones.push_back({1, i});
        } else if (val == 2) {
            twos.push_back({2, i});
        }
    }

    // 2. Check if any valid pair exists
    if (ones.empty() || twos.empty()) {
        return -1;
    }

    // 3. Sort both lists by index
    // Although they are naturally ordered by index based on traversal, 
