        // Advance the pointer pointing to the smaller index
        if (index1 < index2) {
            p1++;
        } else {
            p2++;
        }
    }

    // 5. Return result
    if (min_diff == INT_MAX) {
        // Should not happen if the initial check passed, but as a safeguard
        return -1;
    } else {
        return min_diff;
    }
}
